"""Configuration and provider-aware helpers for CodeGraph."""

from __future__ import annotations

import json
import math
import os
import time
from dataclasses import dataclass
from pathlib import Path
from typing import Any

import tiktoken
from dotenv import load_dotenv

try:
    import requests
except ModuleNotFoundError:  # pragma: no cover - optional dependency at runtime
    requests = None

try:
    from anthropic import Anthropic
except ModuleNotFoundError:  # pragma: no cover - optional dependency at runtime
    Anthropic = None

try:
    from openai import OpenAI
except ModuleNotFoundError:  # pragma: no cover - optional dependency at runtime
    OpenAI = None

load_dotenv()

PROVIDER = os.getenv("LLM_PROVIDER", "ollama").strip().lower()
OLLAMA_BASE_URL = os.getenv("OLLAMA_BASE_URL", "http://localhost:11434")
OLLAMA_MODEL = os.getenv("OLLAMA_MODEL", "llama3.2")
OLLAMA_EMBED_MODEL = os.getenv("OLLAMA_EMBED_MODEL", "nomic-embed-text")
OLLAMA_LLM_TIMEOUT_SECONDS = int(os.getenv("OLLAMA_LLM_TIMEOUT_SECONDS", "360"))
OLLAMA_LLM_RETRIES = int(os.getenv("OLLAMA_LLM_RETRIES", "2"))
OLLAMA_LLM_MAX_PROMPT_CHARS = int(os.getenv("OLLAMA_LLM_MAX_PROMPT_CHARS", "24000"))
OPENAI_API_KEY = os.getenv("OPENAI_API_KEY", "")
ANTHROPIC_API_KEY = os.getenv("ANTHROPIC_API_KEY", "")
NEO4J_URI = os.getenv("NEO4J_URI", "bolt://localhost:7687")
NEO4J_USER = os.getenv("NEO4J_USER", "neo4j")
NEO4J_PASSWORD = os.getenv("NEO4J_PASSWORD", "password")
CHROMA_PATH = os.getenv("CHROMA_PATH", "./chroma_db")
BASE_DIR = Path(__file__).resolve().parents[1]
DATA_DIR = BASE_DIR / "data"
REPOS_DIR = DATA_DIR / "repos"
REPO_MANIFEST_PATH = DATA_DIR / "repo_manifest.json"
EVALS_DIR = BASE_DIR / "evals"
EVAL_QUESTIONS_PATH = BASE_DIR / "backend" / "evaluation" / "eval_questions.json"
FRONTEND_DIR = BASE_DIR / "frontend"
DEFAULT_CHROMA_COLLECTION = os.getenv("CHROMA_COLLECTION", "codegraph_chunks")
USE_LLM_FILE_SUMMARIES = os.getenv("USE_LLM_FILE_SUMMARIES", "false").strip().lower() == "true"


@dataclass(slots=True)
class ProviderStatus:
    """Simple health payload for configured services."""

    provider: str
    llm_model: str
    embed_model: str
    ollama_base_url: str
    chroma_path: str
    neo4j_uri: str


def get_status() -> ProviderStatus:
    """Return the active provider configuration."""

    return ProviderStatus(
        provider=PROVIDER,
        llm_model=get_llm_model(PROVIDER),
        embed_model=get_embedding_model(PROVIDER),
        ollama_base_url=OLLAMA_BASE_URL,
        chroma_path=CHROMA_PATH,
        neo4j_uri=NEO4J_URI,
    )


def ensure_runtime_dirs() -> None:
    """Create the project directories that the pipeline depends on."""

    for path in (DATA_DIR, REPOS_DIR, EVALS_DIR, Path(CHROMA_PATH)):
        path.mkdir(parents=True, exist_ok=True)


def get_llm_model(provider: str | None = None) -> str:
    """Resolve the generation model for the given provider."""

    selected = (provider or PROVIDER).lower()
    if selected == "openai":
        return "gpt-4o-mini"
    if selected == "anthropic":
        return "claude-3-5-haiku-latest"
    return OLLAMA_MODEL


def get_embedding_model(provider: str | None = None) -> str:
    """Resolve the embedding model for the given provider."""

    selected = (provider or PROVIDER).lower()
    if selected == "openai":
        return "text-embedding-3-small"
    return OLLAMA_EMBED_MODEL


def get_token_encoding() -> tiktoken.Encoding:
    """Return a stable tokenizer for rough prompt sizing."""

    try:
        return tiktoken.encoding_for_model("gpt-4o-mini")
    except KeyError:
        return tiktoken.get_encoding("cl100k_base")


def estimate_token_count(text: str) -> int:
    """Estimate token count for a block of text."""

    return len(get_token_encoding().encode(text))


def cosine_distance(vector_a: list[float], vector_b: list[float]) -> float:
    """Compute cosine distance without requiring numpy."""

    if len(vector_a) != len(vector_b):
        raise ValueError("Vectors must have the same dimensionality.")
    dot = sum(a * b for a, b in zip(vector_a, vector_b))
    mag_a = math.sqrt(sum(a * a for a in vector_a))
    mag_b = math.sqrt(sum(b * b for b in vector_b))
    if mag_a == 0 or mag_b == 0:
        return 1.0
    return 1 - (dot / (mag_a * mag_b))


def safe_json_loads(raw_text: str) -> dict[str, Any]:
    """Parse model output into JSON, tolerating fenced blocks and prose noise."""

    cleaned = raw_text.strip()
    if cleaned.startswith("```"):
        cleaned = cleaned.strip("`")
        if cleaned.startswith("json"):
            cleaned = cleaned[4:].strip()
    start = cleaned.find("{")
    end = cleaned.rfind("}")
    if start == -1 or end == -1 or end <= start:
        raise ValueError("No JSON object found in model response.")
    return json.loads(cleaned[start : end + 1])


def _openai_client() -> OpenAI:
    """Create an OpenAI client."""

    if OpenAI is None:
        raise ModuleNotFoundError("openai is not installed. Run `pip install -r backend/requirements.txt`.")
    if not OPENAI_API_KEY:
        raise ValueError("OPENAI_API_KEY is not set.")
    return OpenAI(api_key=OPENAI_API_KEY)


def _anthropic_client() -> Anthropic:
    """Create an Anthropic client."""

    if Anthropic is None:
        raise ModuleNotFoundError("anthropic is not installed. Run `pip install -r backend/requirements.txt`.")
    if not ANTHROPIC_API_KEY:
        raise ValueError("ANTHROPIC_API_KEY is not set.")
    return Anthropic(api_key=ANTHROPIC_API_KEY)


def _require_requests() -> None:
    """Ensure the requests dependency is available before HTTP calls."""

    if requests is None:
        raise ModuleNotFoundError("requests is not installed. Run `pip install -r backend/requirements.txt`.")


def llm_call(prompt: str, system_prompt: str | None = None, provider: str | None = None) -> str:
    """Call the configured LLM provider and return plain text output."""

    selected = (provider or PROVIDER).lower()
    if selected == "openai":
        client = _openai_client()
        response = client.chat.completions.create(
            model=get_llm_model(selected),
            messages=[
                {"role": "system", "content": system_prompt or "You are a precise assistant."},
                {"role": "user", "content": prompt},
            ],
            temperature=0,
        )
        return response.choices[0].message.content or ""

    if selected == "anthropic":
        client = _anthropic_client()
        response = client.messages.create(
            model=get_llm_model(selected),
            system=system_prompt or "You are a precise assistant.",
            messages=[{"role": "user", "content": prompt}],
            temperature=0,
            max_tokens=1500,
        )
        return "".join(block.text for block in response.content if getattr(block, "type", "") == "text")

    _require_requests()
    ollama_prompt = prompt[:OLLAMA_LLM_MAX_PROMPT_CHARS]
    last_error: Exception | None = None
    for attempt in range(OLLAMA_LLM_RETRIES + 1):
        try:
            response = requests.post(
                f"{OLLAMA_BASE_URL.rstrip('/')}/api/generate",
                json={
                    "model": get_llm_model(selected),
                    "prompt": ollama_prompt,
                    "system": system_prompt or "You are a precise assistant.",
                    "stream": False,
                    "options": {"temperature": 0},
                },
                timeout=OLLAMA_LLM_TIMEOUT_SECONDS,
            )
            response.raise_for_status()
            payload = response.json()
            return str(payload.get("response", "")).strip()
        except Exception as exc:
            last_error = exc
            if attempt < OLLAMA_LLM_RETRIES:
                time.sleep(1.2 * (attempt + 1))
    raise RuntimeError(f"Ollama generation failed after retries: {last_error}")


def embed(text: str, provider: str | None = None) -> list[float]:
    """Create an embedding vector for the given text."""

    selected = (provider or PROVIDER).lower()
    if selected == "openai":
        client = _openai_client()
        response = client.embeddings.create(model=get_embedding_model(selected), input=text)
        return [float(value) for value in response.data[0].embedding]

    _require_requests()
    base_url = OLLAMA_BASE_URL.rstrip("/")
    # Keep embedding payload size stable across Ollama model/runtime versions.
    text_for_embedding = text[:8000]
    errors: list[str] = []

    for endpoint, body in (
        ("/api/embed", {"model": get_embedding_model(selected), "input": [text_for_embedding]}),
        ("/api/embeddings", {"model": get_embedding_model(selected), "prompt": text_for_embedding}),
    ):
        try:
            response = requests.post(f"{base_url}{endpoint}", json=body, timeout=180)
            if not response.ok:
                errors.append(f"{endpoint}: {response.status_code}")
                continue
            payload = response.json()
            embedding = payload.get("embedding")
            if isinstance(embedding, list):
                return [float(value) for value in embedding]
            embeddings = payload.get("embeddings")
            if isinstance(embeddings, list) and embeddings and isinstance(embeddings[0], list):
                return [float(value) for value in embeddings[0]]
            errors.append(f"{endpoint}: missing embedding field")
        except Exception as exc:
            errors.append(f"{endpoint}: {exc}")
            continue

    raise ValueError("Ollama embedding endpoint was not found. Tried: " + ", ".join(errors))


def check_ollama_available() -> bool:
    """Return whether the Ollama HTTP endpoint is reachable."""

    if requests is None:
        return False
    try:
        response = requests.get(f"{OLLAMA_BASE_URL.rstrip('/')}/api/tags", timeout=10)
        return response.ok
    except Exception:
        return False

"""tree-sitter based code parsing into graph-friendly structures."""

from __future__ import annotations

import re
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any

from backend.pipeline.repo_loader import RepoFile

try:
    from tree_sitter import Language, Parser
except ModuleNotFoundError:  # pragma: no cover - optional dependency at runtime
    Language = None
    Parser = None

_DOCSTRING_RE = re.compile(r'^\s*(?:"""|\'\'\'|"|\')(.*?)(?:"""|\'\'\'|"|\')', re.DOTALL)
_JS_COMMENT_RE = re.compile(r"/\*\*(.*?)\*/", re.DOTALL)


@dataclass(slots=True)
class ParsedFunction:
    """A parsed function or method."""

    type: str
    name: str
    signature: str
    docstring: str | None
    body: str
    calls: list[str]
    line_start: int
    line_end: int
    file_path: str
    is_method: bool
    parent_class: str | None = None


@dataclass(slots=True)
class ParsedClass:
    """A parsed class."""

    type: str
    name: str
    docstring: str | None
    methods: list[str]
    bases: list[str]
    line_start: int
    line_end: int
    file_path: str


@dataclass(slots=True)
class ParsedImport:
    """A parsed import statement."""

    type: str
    source_file: str
    imported_module: str
    imported_names: list[str]


@dataclass(slots=True)
class ParsedFile:
    """All graph-relevant structures extracted from a source file."""

    file_path: str
    absolute_path: str
    language: str
    module_name: str
    raw_content: str
    functions: list[ParsedFunction] = field(default_factory=list)
    classes: list[ParsedClass] = field(default_factory=list)
    imports: list[ParsedImport] = field(default_factory=list)


class LanguageParser:
    """Base parser API for a single language."""

    language_name: str = ""

    def parse(self, file_path: str, raw_content: str) -> ParsedFile:
        raise NotImplementedError


class UnsupportedLanguageParser(LanguageParser):
    """Fallback parser for languages not yet implemented via tree-sitter."""

    def __init__(self, language_name: str) -> None:
        self.language_name = language_name

    def parse(self, file_path: str, raw_content: str) -> ParsedFile:
        return ParsedFile(
            file_path=file_path,
            absolute_path=file_path,
            language=self.language_name,
            module_name=_module_name(file_path),
            raw_content=raw_content,
        )


class TreeSitterLanguageParser(LanguageParser):
    """Shared helpers for tree-sitter powered parsers."""

    def __init__(self, language_name: str, language_binding: Any) -> None:
        if Language is None or Parser is None:
            raise ModuleNotFoundError(
                "tree-sitter is not installed. Run `pip install -r backend/requirements.txt`."
            )
        self.language_name = language_name
        self.language = _coerce_language(language_binding)
        self.parser = Parser()
        self.parser.language = self.language

    def _parse_tree(self, raw_content: str) -> tuple[Any, bytes]:
        source_bytes = raw_content.encode("utf-8")
        return self.parser.parse(source_bytes), source_bytes

    def _text(self, node: Any, source_bytes: bytes) -> str:
        return source_bytes[node.start_byte : node.end_byte].decode("utf-8", errors="ignore")

    def _walk(self, node: Any) -> list[Any]:
        stack = [node]
        nodes: list[Any] = []
        while stack:
            current = stack.pop()
            nodes.append(current)
            stack.extend(reversed(getattr(current, "children", [])))
        return nodes

    def _find_calls(self, node: Any, source_bytes: bytes) -> list[str]:
        calls: list[str] = []
        seen: set[str] = set()
        for child in self._walk(node):
            if child.type not in {"call", "call_expression"}:
                continue
            target = child.child_by_field_name("function")
            if target is None and getattr(child, "children", []):
                target = child.children[0]
            if target is None:
                continue
            call_name = self._normalize_call_name(target, source_bytes)
            if call_name and call_name not in seen:
                seen.add(call_name)
                calls.append(call_name)
        return calls

    def _normalize_call_name(self, node: Any, source_bytes: bytes) -> str:
        node_text = self._text(node, source_bytes).strip()
        return re.sub(r"\s+", "", node_text)

    def _docstring_from_body(self, body_text: str) -> str | None:
        match = _DOCSTRING_RE.search(body_text.strip())
        return match.group(1).strip() if match else None


class PythonParser(TreeSitterLanguageParser):
    """Python AST extraction using tree-sitter-python."""

    def __init__(self) -> None:
        import tree_sitter_python

        super().__init__("python", tree_sitter_python.language())

    def parse(self, file_path: str, raw_content: str) -> ParsedFile:
        tree, source_bytes = self._parse_tree(raw_content)
        parsed = ParsedFile(
            file_path=file_path,
            absolute_path=file_path,
            language="python",
            module_name=_module_name(file_path),
            raw_content=raw_content,
        )
        class_stack: list[str] = []
        method_map: dict[str, list[str]] = {}

        def visit(node: Any) -> None:
            if node.type == "class_definition":
                class_name = self._text(node.child_by_field_name("name"), source_bytes)
                body_node = node.child_by_field_name("body")
                body_text = self._text(body_node, source_bytes) if body_node else ""
                bases = self._python_bases(node, source_bytes)
                parsed_class = ParsedClass(
                    type="class",
                    name=class_name,
                    docstring=self._docstring_from_body(body_text),
                    methods=[],
                    bases=bases,
                    line_start=node.start_point[0] + 1,
                    line_end=node.end_point[0] + 1,
                    file_path=file_path,
                )
                parsed.classes.append(parsed_class)
                method_map[class_name] = parsed_class.methods
                class_stack.append(class_name)
                for child in node.children:
                    visit(child)
                class_stack.pop()
                return

            if node.type == "function_definition":
                name = self._text(node.child_by_field_name("name"), source_bytes)
                body_node = node.child_by_field_name("body")
                body_text = self._text(node, source_bytes)
                signature = body_text.splitlines()[0].strip()
                function = ParsedFunction(
                    type="function",
                    name=name,
                    signature=signature,
                    docstring=self._docstring_from_body(self._text(body_node, source_bytes) if body_node else ""),
                    body=body_text,
                    calls=self._find_calls(node, source_bytes),
                    line_start=node.start_point[0] + 1,
                    line_end=node.end_point[0] + 1,
                    file_path=file_path,
                    is_method=bool(class_stack),
                    parent_class=class_stack[-1] if class_stack else None,
                )
                parsed.functions.append(function)
                if class_stack:
                    method_map[class_stack[-1]].append(name)
                return

            if node.type in {"import_statement", "import_from_statement"}:
                parsed_import = self._parse_import(node, source_bytes, file_path)
                if parsed_import:
                    parsed.imports.append(parsed_import)

            for child in node.children:
                visit(child)

        visit(tree.root_node)
        return parsed

    def _python_bases(self, node: Any, source_bytes: bytes) -> list[str]:
        bases: list[str] = []
        for child in node.children:
            if child.type == "argument_list":
                for grandchild in child.children:
                    if grandchild.type in {"identifier", "attribute"}:
                        bases.append(self._text(grandchild, source_bytes).strip())
        return bases

    def _parse_import(self, node: Any, source_bytes: bytes, file_path: str) -> ParsedImport | None:
        raw = self._text(node, source_bytes).strip()
        if node.type == "import_statement":
            modules = [part.strip() for part in raw.removeprefix("import ").split(",") if part.strip()]
            imported_module = modules[0].split(" as ")[0].strip() if modules else ""
            names = [module.split(" as ")[0].strip().split(".")[-1] for module in modules]
            if imported_module:
                return ParsedImport(
                    type="import",
                    source_file=file_path,
                    imported_module=imported_module,
                    imported_names=names,
                )
            return None

        match = re.match(r"from\s+([^\s]+)\s+import\s+(.+)", raw)
        if not match:
            return None
        imported_module = match.group(1).strip()
        imported_names = [
            name.strip().split(" as ")[0].strip()
            for name in match.group(2).split(",")
            if name.strip()
        ]
        return ParsedImport(
            type="import",
            source_file=file_path,
            imported_module=imported_module,
            imported_names=imported_names,
        )


class JavaScriptParser(TreeSitterLanguageParser):
    """JavaScript AST extraction using tree-sitter-javascript."""

    def __init__(self) -> None:
        import tree_sitter_javascript

        super().__init__("javascript", tree_sitter_javascript.language())

    def parse(self, file_path: str, raw_content: str) -> ParsedFile:
        tree, source_bytes = self._parse_tree(raw_content)
        parsed = ParsedFile(
            file_path=file_path,
            absolute_path=file_path,
            language="javascript",
            module_name=_module_name(file_path),
            raw_content=raw_content,
        )
        class_methods: dict[str, list[str]] = {}

        def visit(node: Any, active_class: str | None = None) -> None:
            if node.type == "class_declaration":
                name_node = node.child_by_field_name("name")
                class_name = self._text(name_node, source_bytes) if name_node else "AnonymousClass"
                bases = []
                heritage = node.child_by_field_name("heritage")
                if heritage is not None:
                    bases.append(self._text(heritage, source_bytes).replace("extends", "").strip())
                parsed_class = ParsedClass(
                    type="class",
                    name=class_name,
                    docstring=_extract_js_docstring(raw_content, node.start_byte),
                    methods=[],
                    bases=bases,
                    line_start=node.start_point[0] + 1,
                    line_end=node.end_point[0] + 1,
                    file_path=file_path,
                )
                parsed.classes.append(parsed_class)
                class_methods[class_name] = parsed_class.methods
                for child in node.children:
                    visit(child, class_name)
                return

            function = self._js_function_from_node(node, source_bytes, file_path, active_class)
            if function is not None:
                parsed.functions.append(function)
                if active_class:
                    class_methods[active_class].append(function.name)

            if node.type == "import_statement":
                parsed.imports.append(self._js_import(node, source_bytes, file_path))

            for child in node.children:
                visit(child, active_class)

        visit(tree.root_node)
        return parsed

    def _js_function_from_node(
        self, node: Any, source_bytes: bytes, file_path: str, active_class: str | None
    ) -> ParsedFunction | None:
        if node.type == "function_declaration":
            name_node = node.child_by_field_name("name")
            body_node = node.child_by_field_name("body")
            body_text = self._text(node, source_bytes)
            return ParsedFunction(
                type="function",
                name=self._text(name_node, source_bytes) if name_node else "anonymous",
                signature=body_text.splitlines()[0].strip(),
                docstring=_extract_js_docstring(body_text, 0),
                body=body_text,
                calls=self._find_calls(node, source_bytes),
                line_start=node.start_point[0] + 1,
                line_end=node.end_point[0] + 1,
                file_path=file_path,
                is_method=False,
            )

        if node.type == "method_definition":
            name_node = node.child_by_field_name("name")
            body_node = node.child_by_field_name("body") or node.child_by_field_name("value")
            body_text = self._text(node, source_bytes)
            return ParsedFunction(
                type="function",
                name=self._text(name_node, source_bytes) if name_node else "method",
                signature=body_text.splitlines()[0].strip(),
                docstring=_extract_js_docstring(body_text, 0),
                body=body_text if body_node is None else self._text(node, source_bytes),
                calls=self._find_calls(node, source_bytes),
                line_start=node.start_point[0] + 1,
                line_end=node.end_point[0] + 1,
                file_path=file_path,
                is_method=True,
                parent_class=active_class,
            )

        if node.type == "lexical_declaration":
            declarator = next((child for child in node.children if child.type == "variable_declarator"), None)
            if declarator is None:
                return None
            value = declarator.child_by_field_name("value")
            if value is None or value.type not in {"arrow_function", "function"}:
                return None
            name_node = declarator.child_by_field_name("name")
            body_text = self._text(node, source_bytes)
            return ParsedFunction(
                type="function",
                name=self._text(name_node, source_bytes) if name_node else "anonymous",
                signature=body_text.splitlines()[0].strip(),
                docstring=_extract_js_docstring(body_text, 0),
                body=body_text,
                calls=self._find_calls(value, source_bytes),
                line_start=node.start_point[0] + 1,
                line_end=node.end_point[0] + 1,
                file_path=file_path,
                is_method=False,
            )
        return None

    def _js_import(self, node: Any, source_bytes: bytes, file_path: str) -> ParsedImport:
        raw = self._text(node, source_bytes)
        module_match = re.search(r'from\s+[\'"]([^\'"]+)[\'"]', raw)
        imported_module = module_match.group(1) if module_match else ""
        names = re.findall(r"{([^}]+)}", raw)
        imported_names = []
        if names:
            imported_names = [name.strip() for name in names[0].split(",") if name.strip()]
        return ParsedImport(
            type="import",
            source_file=file_path,
            imported_module=imported_module,
            imported_names=imported_names,
        )


class TypeScriptParser(JavaScriptParser):
    """TypeScript AST extraction using tree-sitter-typescript."""

    def __init__(self) -> None:
        import tree_sitter_typescript

        language_binding = getattr(tree_sitter_typescript, "language_typescript", None)
        if not callable(language_binding):
            raise AttributeError("tree_sitter_typescript.language_typescript is unavailable.")
        TreeSitterLanguageParser.__init__(self, "typescript", language_binding())


def get_parser(language: str) -> LanguageParser:
    """Return the parser instance for a given language."""

    try:
        if language == "python":
            return PythonParser()
        if language == "javascript":
            return JavaScriptParser()
        if language == "typescript":
            return TypeScriptParser()
    except Exception:
        return UnsupportedLanguageParser(language)
    return UnsupportedLanguageParser(language)


def parse_repo_files(repo_files: list[RepoFile]) -> list[ParsedFile]:
    """Parse all repo files into graph-friendly structures."""

    parsed_files: list[ParsedFile] = []
    for repo_file in repo_files:
        parser = get_parser(repo_file.language)
        parsed = parser.parse(repo_file.file_path, repo_file.raw_content)
        parsed.absolute_path = repo_file.absolute_path
        parsed_files.append(parsed)
    return parsed_files


def _module_name(file_path: str) -> str:
    path = Path(file_path)
    if path.suffix == ".py":
        return ".".join(path.with_suffix("").parts)
    return path.with_suffix("").as_posix().replace("/", ".")


def _extract_js_docstring(text: str, end_offset: int) -> str | None:
    matches = list(_JS_COMMENT_RE.finditer(text[:end_offset]))
    if not matches:
        return None
    return re.sub(r"^\s*\*\s?", "", matches[-1].group(1), flags=re.MULTILINE).strip() or None


def _coerce_language(language_binding: Any) -> Any:
    """Handle tree-sitter >=0.21 bindings across minor package variations."""

    try:
        return Language(language_binding)
    except Exception:
        return language_binding

"""Embedding generation and ChromaDB storage for semantic code units."""

from __future__ import annotations

from dataclasses import dataclass
from typing import Any

try:
    import chromadb
except ModuleNotFoundError:  # pragma: no cover - optional dependency at runtime
    chromadb = None

from backend.config import CHROMA_PATH, DEFAULT_CHROMA_COLLECTION, PROVIDER, USE_LLM_FILE_SUMMARIES, embed, llm_call
from backend.pipeline.code_parser import ParsedFile


@dataclass(slots=True)
class EmbeddingChunk:
    """A semantic code chunk stored in ChromaDB."""

    chunk_id: str
    text: str
    metadata: dict[str, Any]


def get_chroma_collection(collection_name: str = DEFAULT_CHROMA_COLLECTION) -> Any:
    """Return a persistent Chroma collection."""

    if chromadb is None:
        raise ModuleNotFoundError("chromadb is not installed. Run `pip install -r backend/requirements.txt`.")
    client = chromadb.PersistentClient(path=CHROMA_PATH)
    return client.get_or_create_collection(name=collection_name, metadata={"hnsw:space": "cosine"})


def reset_chroma_collection(collection_name: str = DEFAULT_CHROMA_COLLECTION) -> None:
    """Delete and recreate the active Chroma collection."""

    if chromadb is None:
        raise ModuleNotFoundError("chromadb is not installed. Run `pip install -r backend/requirements.txt`.")
    client = chromadb.PersistentClient(path=CHROMA_PATH)
    try:
        client.delete_collection(collection_name)
    except Exception:
        pass
    client.get_or_create_collection(name=collection_name, metadata={"hnsw:space": "cosine"})


class CodeEmbedder:
    """Build and store semantic code chunks."""

    def __init__(self, collection_name: str = DEFAULT_CHROMA_COLLECTION) -> None:
        self.collection_name = collection_name

    def build_chunks(
        self,
        parsed_files: list[ParsedFile],
        provider: str | None = None,
        progress_callback: Any | None = None,
    ) -> list[EmbeddingChunk]:
        """Create semantic chunks for functions, classes, and file summaries."""

        chunks: list[EmbeddingChunk] = []
        total_files = max(len(parsed_files), 1)
        for index, parsed_file in enumerate(parsed_files, start=1):
            for function in parsed_file.functions:
                chunks.append(
                    EmbeddingChunk(
                        chunk_id=f"{function.file_path}::{function.name}",
                        text=function.body,
                        metadata={
                            "chunk_id": f"{function.file_path}::{function.name}",
                            "type": "function",
                            "name": function.name,
                            "file_path": function.file_path,
                            "language": parsed_file.language,
                            "signature": function.signature,
                            "line_start": function.line_start,
                            "line_end": function.line_end,
                        },
                    )
                )

            for parsed_class in parsed_file.classes:
                method_signatures = []
                for function in parsed_file.functions:
                    if function.parent_class == parsed_class.name:
                        method_signatures.append(function.signature)
                class_text = "\n".join(
                    [f"class {parsed_class.name}", parsed_class.docstring or "", *method_signatures]
                ).strip()
                chunks.append(
                    EmbeddingChunk(
                        chunk_id=f"{parsed_class.file_path}::{parsed_class.name}",
                        text=class_text,
                        metadata={
                            "chunk_id": f"{parsed_class.file_path}::{parsed_class.name}",
                            "type": "class",
                            "name": parsed_class.name,
                            "file_path": parsed_class.file_path,
                            "language": parsed_file.language,
                            "signature": "",
                            "line_start": parsed_class.line_start,
                            "line_end": parsed_class.line_end,
                        },
                    )
                )

            summary = self._summarize_file(parsed_file, provider)
            chunks.append(
                EmbeddingChunk(
                    chunk_id=f"{parsed_file.file_path}::__file_summary__",
                    text=summary,
                    metadata={
                        "chunk_id": f"{parsed_file.file_path}::__file_summary__",
                        "type": "file_summary",
                        "name": parsed_file.file_path,
                        "file_path": parsed_file.file_path,
                        "language": parsed_file.language,
                        "signature": "",
                        "line_start": 1,
                        "line_end": max(1, len(parsed_file.raw_content.splitlines())),
                    },
                    )
                )
            if progress_callback is not None:
                progress_callback(index, total_files, len(chunks))
        return chunks

    def store(
        self,
        parsed_files: list[ParsedFile],
        provider: str | None = None,
        progress_callback: Any | None = None,
    ) -> dict[str, int]:
        """Embed semantic code chunks and persist them to ChromaDB."""

        collection = get_chroma_collection(self.collection_name)
        chunks = self.build_chunks(parsed_files, provider or PROVIDER)
        total_chunks = max(len(chunks), 1)
        for index, chunk in enumerate(chunks, start=1):
            collection.upsert(
                ids=[chunk.chunk_id],
                documents=[chunk.text],
                embeddings=[embed(chunk.text, provider or PROVIDER)],
                metadatas=[chunk.metadata],
            )
            if progress_callback is not None:
                progress_callback(index, total_chunks, chunk)
        return {"chunks_embedded": len(chunks)}

    def delete_file(self, file_path: str) -> None:
        """Delete all chunks associated with a file."""

        collection = get_chroma_collection(self.collection_name)
        try:
            collection.delete(where={"file_path": file_path})
        except Exception:
            pass

    def _summarize_file(self, parsed_file: ParsedFile, provider: str | None = None) -> str:
        """Generate a compact file summary for retrieval."""

        symbol_list = ", ".join(
            [function.name for function in parsed_file.functions[:8]]
            + [parsed_class.name for parsed_class in parsed_file.classes[:8]]
        )
        if not USE_LLM_FILE_SUMMARIES:
            if parsed_file.functions or parsed_file.classes:
                return (
                    f"This file contains {len(parsed_file.functions)} functions and "
                    f"{len(parsed_file.classes)} classes. Key symbols: {symbol_list or parsed_file.file_path}."
                )
            return f"This file contains {parsed_file.language} source code at {parsed_file.file_path}."
        prompt = (
            "Summarize this source file in 1-2 sentences. "
            "Start with 'This file contains...'. "
            f"Language: {parsed_file.language}\n"
            f"Path: {parsed_file.file_path}\n"
            f"Symbols: {symbol_list or 'None'}\n"
            f"Code:\n{parsed_file.raw_content[:6000]}"
        )
        try:
            return llm_call(prompt, system_prompt="You summarize code files precisely.", provider=provider or PROVIDER)
        except Exception:
            if parsed_file.functions or parsed_file.classes:
                return (
                    f"This file contains {len(parsed_file.functions)} functions and "
                    f"{len(parsed_file.classes)} classes: {symbol_list or parsed_file.file_path}."
                )
            return f"This file contains {parsed_file.language} source code at {parsed_file.file_path}."

"""Semantic vector retrieval over ChromaDB for code chunks."""

from __future__ import annotations

from pathlib import PurePosixPath
from typing import Any

from backend.config import DEFAULT_CHROMA_COLLECTION, PROVIDER, embed
from backend.pipeline.embedder import get_chroma_collection


def vector_search(
    query: str,
    top_k: int = 5,
    provider: str | None = None,
    collection_name: str = DEFAULT_CHROMA_COLLECTION,
) -> list[dict[str, Any]]:
    """Retrieve the nearest code chunk matches from ChromaDB."""

    if top_k <= 0:
        return []
    collection = get_chroma_collection(collection_name)
    query_embedding = embed(query, provider or PROVIDER)
    try:
        results = collection.query(query_embeddings=[query_embedding], n_results=top_k)
    except Exception:
        return []

    matches: list[dict[str, Any]] = []
    ids = results.get("ids", [[]])[0]
    documents = results.get("documents", [[]])[0]
    distances = results.get("distances", [[]])[0]
    metadatas = results.get("metadatas", [[]])[0]

    for chunk_id, document, distance, metadata in zip(ids, documents, distances, metadatas):
        row = dict(metadata or {})
        row.update(
            {
                "chunk_id": str(chunk_id),
                "text": str(document),
                "distance": float(distance),
            }
        )
        matches.append(row)
    return sorted(matches, key=_rank_key)


def _rank_key(match: dict[str, Any]) -> tuple[float, float]:
    file_path = str(match.get("file_path", ""))
    penalty = _path_penalty(file_path)
    return (penalty, float(match.get("distance", 1.0)))


def _path_penalty(file_path: str) -> float:
    path = PurePosixPath(file_path.lower())
    parts = set(path.parts)
    if "src" in parts:
        return 0.0
    if "itsdangerous" in parts and "tests" not in parts:
        return 0.05
    if "tests" in parts or "test" in parts:
        return 0.8
    if "scripts" in parts:
        return 0.95
    if "docs" in parts or "docs_src" in parts or "examples" in parts:
        return 0.9
    return 0.2
